"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Stepper Context ──────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"

interface StepperContextValue {
  value: number
  onValueChange: (value: number) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error(
      "Stepper sub-components must be rendered inside a <Stepper>."
    )
  }
  return context
}

// ─── StepperItem Context ──────────────────────────────────────────────────────

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

// ─── Stepper ──────────────────────────────────────────────────────────────────

interface StepperProps extends React.ComponentProps<"div"> {
  /** The currently active step (1-indexed). Use with `onValueChange` for
   *  controlled behaviour; omit for uncontrolled. */
  value?: number
  /** Initial active step when used as an uncontrolled component (default: 1). */
  defaultValue?: number
  /** Callback fired when the active step changes. */
  onValueChange?: (value: number) => void
  /** Visual and interaction layout direction (default: "horizontal"). */
  orientation?: StepperOrientation
}

function Stepper({
  value: valueProp,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (step: number) => {
      if (!isControlled) {
        setInternalValue(step)
      }
      onValueChange?.(step)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          // Horizontal: items + separators share a row; content panels wrap below.
          orientation === "horizontal" && "flex-row flex-wrap items-center",
          // Vertical: items stack in a column.
          orientation === "vertical" && "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** The step number this item represents (1-indexed). */
  step: number
  /** Explicitly mark the step as completed, overriding the default
   *  auto-completion heuristic (`value > step`). */
  completed?: boolean
  /** Prevents the user from navigating to this step via its trigger. */
  disabled?: boolean
}

function StepperItem({
  step,
  completed: completedProp,
  disabled = false,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { value, orientation } = useStepperContext()
  const isActive = value === step
  const isCompleted = completedProp ?? value > step
  const isDisabled = disabled

  return (
    <StepperItemContext.Provider
      value={{ step, isActive, isCompleted, isDisabled }}
    >
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
        data-disabled={isDisabled || undefined}
        className={cn(
          "group/stepper-item shrink-0",
          // In vertical mode the item stacks its trigger, separator, and
          // optional inline content from top to bottom.
          orientation === "vertical" && "flex flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange, orientation } = useStepperContext()
  const { step, isActive, isCompleted, isDisabled } =
    React.useContext(StepperItemContext)!

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      disabled={isDisabled}
      onClick={() => onValueChange(step)}
      className={cn(
        "flex cursor-pointer items-center gap-2 rounded-md py-1.5 text-left",
        "outline-none transition-colors",
        "hover:bg-accent/50",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        // Fill the available width when stacked vertically so the hover
        // highlight spans the full item.
        orientation === "vertical" && "w-full",
        className
      )}
      {...props}
    >
      {/* ── Step indicator bubble ──────────────────────────────────────── */}
      <span
        data-slot="stepper-indicator"
        aria-hidden="true"
        className={cn(
          "flex size-8 shrink-0 select-none items-center justify-center",
          "rounded-full border-2 text-sm font-semibold transition-colors",
          isCompleted || isActive
            ? "border-primary bg-primary text-primary-foreground"
            : "border-border bg-background text-muted-foreground"
        )}
      >
        {isCompleted ? <CheckIcon className="size-4" /> : step}
      </span>

      {/* ── Optional label area (StepperTitle + StepperDescription) ───── */}
      {children && <div className="flex flex-col gap-0.5">{children}</div>}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { isActive, isCompleted } = React.useContext(StepperItemContext)!
  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium leading-none transition-colors",
        isActive || isCompleted ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

interface StepperSeparatorProps extends React.ComponentProps<"div"> {
  /**
   * Explicitly marks this separator as belonging to a completed transition.
   * Only needed for horizontal separators placed outside a `StepperItem`
   * (vertical separators infer completion automatically from item context).
   */
  completed?: boolean
}

function StepperSeparator({
  completed: completedProp,
  className,
  ...props
}: StepperSeparatorProps) {
  const { orientation } = useStepperContext()
  const itemContext = React.useContext(StepperItemContext)

  // Vertical separator inside a StepperItem: inherit completion from context.
  // Horizontal separator between StepperItems: use the explicit prop.
  const isCompleted = completedProp ?? itemContext?.isCompleted ?? false

  return (
    <div
      role="none"
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "shrink-0 bg-border transition-colors",
        // Horizontal: grow to fill space between step items; 1-px tall line.
        orientation === "horizontal" &&
          "mx-2 h-px flex-1 self-center min-w-6",
        // Vertical: thin vertical line indented so it falls under the centre
        // of the size-8 (32 px) indicator bubble.
        // centre = 16 px; line is 1 px wide → left edge at 15.5 px ≈ ms-[15px]
        orientation === "vertical" && "ms-[15px] w-px min-h-6",
        isCompleted && "bg-primary",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

interface StepperContentProps extends React.ComponentProps<"div"> {
  /**
   * The step whose content this panel displays.
   * - **Required** when placed outside a `StepperItem` (typical horizontal usage).
   * - **Optional** when placed inside a `StepperItem`; inferred from context.
   */
  step?: number
}

function StepperContent({
  step: stepProp,
  className,
  ...props
}: StepperContentProps) {
  const { value } = useStepperContext()
  const itemContext = React.useContext(StepperItemContext)
  const step = stepProp ?? itemContext?.step
  const isActive = step !== undefined && value === step

  return (
    <div
      data-slot="stepper-content"
      data-state={isActive ? "active" : "inactive"}
      // Use the HTML hidden attribute so inactive panels are removed from
      // the accessibility tree and take no layout space.
      hidden={!isActive}
      className={cn(
        // Outside a StepperItem (horizontal): break to a full-width row
        // below all step items by using order-last + basis-full.
        !itemContext && "basis-full order-last mt-4",
        // Inside a StepperItem (vertical): indent to align with the text
        // column that starts after the indicator (size-8 = 32 px) + gap
        // (gap-2 = 8 px) = 40 px = ms-10.
        itemContext && "ms-10 pb-6",
        className
      )}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

